// Simula chegada irregular de pedidos: só ~40% das execuções
// do cron realmente vira pedido. A escolha da unidade acontece
// DEPOIS, com base no que o servidor disser que está aberto.
const CHANCE_DE_DISPARAR = 0.4;
if (Math.random() > CHANCE_DE_DISPARAR) {
  return [];
}

// ~90% iFood, ~5% Rappi, ~5% próprio — mesma distribuição do seed
const r = Math.random();
const plataforma = r < 0.9 ? "ifood" : r < 0.95 ? "rappi" : "proprio";

return [{ json: { plataforma } }];

// O servidor é a fonte de verdade: só unidades ABERTAS agora e
// com itens disponíveis no cardápio podem receber pedido.
const { plataforma } = $("Sorteia disparo e plataforma").first().json;
const unidades = ($json.unidades || []).filter(
  (u) => u.aberta && (u.cardapio || []).length > 0
);
if (unidades.length === 0) {
  return []; // rede fechada — nenhum pedido nasce fora do horário
}

const u = unidades[Math.floor(Math.random() * unidades.length)];

const embaralhado = [...u.cardapio].sort(() => Math.random() - 0.5);
const quantidadeItens = 1 + Math.floor(Math.random() * Math.min(4, embaralhado.length));
const itens = embaralhado.slice(0, quantidadeItens).map((p) => ({
  produto_id: p.produto_id,
  quantidade: 1 + Math.floor(Math.random() * 3),
}));

return [{ json: { unidade_id: u.unidade_id, plataforma, itens } }];
